import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"General (New)","description":"","frontmatter":{"title":"General (New)","slug":"general-new"},"headers":[],"relativePath":"account-hub/general-new.md","filePath":"account-hub/general-new.md"}'),r={name:"account-hub/general-new.md"};function i(s,e,p,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The General tab is where you configure the core details of your Branch account. Use this page to manage your app&#39;s basic information, including your app name, app ID, logo, timezone, and currency preferences.</p><p>To access this tab, select your avatar in the top-left corner of Branch, then select <strong>App Settings</strong>. On this page, the <strong>General</strong> tab is selected by default.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this feature yet?</p><p>The General tab is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p><p>In the meantime, please continue to refer to our <a href="./user-accounts-and-permissions.html">legacy documentation on managing your account profile</a>.</p></div><h2 id="configure-settings" tabindex="-1">Configure settings <a class="header-anchor" href="#configure-settings" aria-label="Permalink to &quot;Configure settings&quot;">​</a></h2><p>The General tab includes the following configuration options:</p><h3 id="app-name" tabindex="-1">App name <a class="header-anchor" href="#app-name" aria-label="Permalink to &quot;App name&quot;">​</a></h3><p>This is your app name as it appears throughout Branch. Your app name helps you identify your account and appears in various places across the platform.</p><p>You can update your app name at any time by entering a new value in this field.</p><h3 id="app-id" tabindex="-1">App ID <a class="header-anchor" href="#app-id" aria-label="Permalink to &quot;App ID&quot;">​</a></h3><p>This is the unique key provided by Branch that identifies your app within the Branch platform. Branch uses this identifier to associate data and events with your specific app.</p><p>You can copy your app ID by using the <strong>copy icon</strong> next to the field. You&#39;ll need this ID when <a href="./branch-sdks.html">integrating the Branch SDK</a> into your app.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Your app ID is sensitive information. Keep it secure and do not share it publicly.</p></div><h3 id="app-logo" tabindex="-1">App logo <a class="header-anchor" href="#app-logo" aria-label="Permalink to &quot;App logo&quot;">​</a></h3><p>Upload your company or app logo to personalize your Branch experience. Your logo will appear in the top-left corner of Branch.</p><p>To upload a logo, select the upload icon and select an image file from your computer.</p><h3 id="timezone" tabindex="-1">Timezone <a class="header-anchor" href="#timezone" aria-label="Permalink to &quot;Timezone&quot;">​</a></h3><p>Select the timezone that Branch will use to display dates and times throughout the platform. This affects how analytics data, reports, and timestamps are displayed.</p><p>Setting the correct timezone ensures that your data is displayed accurately and aligns with your team&#39;s working hours.</p><h3 id="local-currency" tabindex="-1">Local currency <a class="header-anchor" href="#local-currency" aria-label="Permalink to &quot;Local currency&quot;">​</a></h3><p>Select the currency that Branch will use to display monetary values in your reports and dashboards. This setting affects how revenue and cost data is presented throughout the platform.</p><p>Choose the currency that aligns with your primary business operations and reporting needs.</p><h2 id="save-changes" tabindex="-1">Save changes <a class="header-anchor" href="#save-changes" aria-label="Permalink to &quot;Save changes&quot;">​</a></h2><p>After making any changes to your General settings, select the <strong>Save Changes</strong> button in the top-right corner of the page to apply your updates.</p><p>Branch will save your settings and apply them immediately.</p>',25)])])}const g=a(r,[["render",i]]);export{d as __pageData,g as default};
